outputs.main.sas:
libname raw "path_to_raw_data";
libname sdtm "path_to_sdtm_output";

* Read raw related records data;
data raw_relrec;
  set raw.relrec_raw;
run;

* Sort by subject and sequence;
proc sort data=raw_relrec;
  by usubjid relrecseq;
run;

* Create SDTM RELREC dataset;
data sdtm.relrec (label="Related Records");
  length
    STUDYID $12
    DOMAIN $2
    USUBJID $11
    RELRECSEQ 8
    RDOMAIN $2
    IDVAR $8
    IDVARVAL $200
    RELTYPE $1
    RELID $20
  ;

  retain
    STUDYID "CDISCPILOT01"
    DOMAIN "RELREC"
  ;

  set raw_relrec;
  by usubjid relrecseq;

  * Derive USUBJID if not present;
  if missing(USUBJID) then USUBJID = cats(STUDYID, "-", SUBJID);

  * Derive RELRECSEQ (sequential numbering per subject);
  if first.usubjid then relrecseq = 0;
  relrecseq + 1;

  * Map key variables;
  * RDOMAIN: Related domain abbreviation;
  * IDVAR: Identifier variable name in related domain;
  * IDVARVAL: Value of the identifier variable;
  * RELTYPE: Relationship type (1=one-to-one, 2=one-to-many, etc.);
  * RELID: Relationship identifier linking related records;

  * Apply variable attributes per SDTM specification;
  label
    STUDYID = "Study Identifier"
    DOMAIN = "Domain Abbreviation"
    USUBJID = "Unique Subject Identifier"
    RELRECSEQ = "Sequence Number"
    RDOMAIN = "Related Domain Abbreviation"
    IDVAR = "Identifying Variable"
    IDVARVAL = "Identifying Variable Value"
    RELTYPE = "Relationship Type"
    RELID = "Relationship Identifier"
  ;

  format
    RELRECSEQ best.
  ;

  * Keep only required variables;
  keep STUDYID DOMAIN USUBJID RELRECSEQ RDOMAIN IDVAR IDVARVAL RELTYPE RELID;
run;

* Create permanent SAS dataset with xport format;
proc copy in=sdtm out=work;
  select relrec;
run;

proc export data=work.relrec
  outfile="path_to_output/relrec.xpt"
  dbms=xport
  replace;
run;
